  1	import React, { useEffect, useState } from 'react';
  2	
  3	import { IoK8sApiCoreV1Service } from '@kubevirt-ui/kubevirt-api/kubernetes';
  4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import Loading from '@kubevirt-utils/components/Loading/Loading';
  6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  7	import {
  8	  Alert,
  9	  AlertVariant,
 10	  ClipboardCopy,
 11	  DescriptionListDescription,
 12	  DescriptionListGroup,
 13	  DescriptionListTerm,
 14	  Flex,
 15	  FlexItem,
 16	  Stack,
 17	  StackItem,
 18	} from '@patternfly/react-core';
 19	
 20	import { SERVICE_TYPES } from '../constants';
 21	import useSSHCommand, { isLoadBalancerBonded } from '../useSSHCommand';
 22	import { createSSHService, deleteSSHService } from '../utils';
 23	
 24	import SSHServiceSelect from './SSHServiceSelect';
 25	import SSHServiceStateIcon from './SSHServiceState';
 26	
 27	type SSHCommandProps = {
 28	  sshService: IoK8sApiCoreV1Service;
 29	  sshServiceLoaded?: boolean;
 30	  vm: V1VirtualMachine;
 31	};
 32	
 33	const SSHCommand: React.FC<SSHCommandProps> = ({
 34	  sshService: initialSSHService,
 35	  sshServiceLoaded,
 36	  vm,
 37	}) => {
 38	  const { t } = useKubevirtTranslation();
 39	  const [sshService, setSSHService] = useState<IoK8sApiCoreV1Service | null>();
 40	  const { command, sshServiceRunning } = useSSHCommand(vm, sshService);
 41	  const [loading, setLoading] = useState(false);
 42	  const [error, setError] = useState<Error>();
 43	
 44	  const onSSHChange = async (newServiceType: SERVICE_TYPES) => {
 45	    setLoading(true);
 46	
 47	    try {
 48	      if (sshService) {
 49	        await deleteSSHService(sshService);
 50	        setSSHService(null);
 51	      }
 52	
 53	      if (newServiceType && newServiceType !== SERVICE_TYPES.NONE) {
 54	        const newService = await createSSHService(vm, newServiceType);
 55	        setSSHService(newService);
 56	      }
 57	    } catch (apiError) {
 58	      setError(apiError);
 59	    } finally {
 60	      setLoading(false);
 61	    }
 62	  };
 63	
 64	  useEffect(() => {
 65	    setSSHService(initialSSHService);
 66	    setError(undefined);
 67	  }, [initialSSHService]);
 68	
 69	  const showBondingWarning =
 70	    sshService?.spec?.type === SERVICE_TYPES.LOAD_BALANCER && !isLoadBalancerBonded(sshService);
 71	
 72	  return (
 73	    <DescriptionListGroup className="pf-v6-c-description-list__group">
 74	      <DescriptionListTerm className="pf-v6-u-font-size-xs">
 75	        {t('SSH service type')}
 76	      </DescriptionListTerm>
 77	
 78	      <DescriptionListDescription className="pf-v6-c-description-list__description">
 79	        <Stack hasGutter>
 80	          {sshServiceLoaded && !loading ? (
 81	            <>
 82	              <StackItem>
 83	                <Flex direction={{ default: 'row' }}>
 84	                  <FlexItem flex={{ default: 'flex_1' }}>
 85	                    <SSHServiceSelect
 86	                      onSSHChange={onSSHChange}
 87	                      sshService={sshService}
 88	                      sshServiceLoaded={sshServiceLoaded}
 89	                    />
 90	                  </FlexItem>
 91	
 92	                  <SSHServiceStateIcon
 93	                    sshService={sshService}
 94	                    sshServiceLoaded={sshServiceLoaded}
 95	                  />
 96	                </Flex>
 97	              </StackItem>
 98	
 99	              {sshServiceRunning && !showBondingWarning && (
100	                <StackItem>
101	                  <ClipboardCopy
102	                    clickTip={t('Copied')}
103	                    data-test="ssh-command-copy"
104	                    hoverTip={t('Copy to clipboard')}
105	                    isReadOnly
106	                  >
107	                    {command}
108	                  </ClipboardCopy>
109	                </StackItem>
110	              )}
111	            </>
112	          ) : (
113	            <Loading />
114	          )}
115	          {error && (
116	            <StackItem>
117	              <Alert isInline title={t('Error')} variant={AlertVariant.danger}>
118	                {error?.message}
119	              </Alert>
120	            </StackItem>
121	          )}
122	        </Stack>
123	      </DescriptionListDescription>
124	    </DescriptionListGroup>
125	  );
126	};
127	
128	export default SSHCommand;

